#include <stdlib.h>
#include <stdio.h>

#include "../common.h"
#include "../util/timer/timer.h"

__global__ void kernel_gpu(int order, long maxheight, int count,
                           knode *knodes, long knodes_elem,
                           long *currKnode, long *offset,
                           int *keys, record *ans,
                           record *records) {
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    int threadsPerBlock = (order < 1024) ? order : 1024;

    for (int i = 0; i < maxheight; i++) {
        __shared__ long shared_offset;
        if (thid == 0) shared_offset = offset[bid];
        __syncthreads();

        if (thid < threadsPerBlock) {
            int curr_node = currKnode[bid];
            if (curr_node < knodes_elem) {
                int key_left = knodes[curr_node].keys[thid];
                int key_right = knodes[curr_node].keys[thid + 1];
                int key = keys[bid];
                if (key_left <= key && key_right > key) {
                    int idx = knodes[curr_node].indices[thid];
                    if (idx < knodes_elem) {
                        atomicMin(&shared_offset, idx);
                    }
                }
            }
        }
        __syncthreads();
        if (thid == 0) {
            offset[bid] = shared_offset;
            currKnode[bid] = shared_offset;
        }
        __syncthreads();
    }

    if (thid < threadsPerBlock) {
        int curr_node = currKnode[bid];
        if (curr_node < knodes_elem) {
            if (knodes[curr_node].keys[thid] == keys[bid]) {
                ans[bid].value = records[knodes[curr_node].indices[thid]].value;
            }
        }
    }
}

void kernel_cpu(int cores_arg,
                record *records,
                knode *knodes,
                long knodes_elem,
                int order,
                long maxheight,
                int count,
                long *currKnode,
                long *offset,
                int *keys,
                record *ans) {

    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    time1 = get_time();

    // Allocate device memory
    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc((void **)&d_records, sizeof(record) * knodes_elem);
    cudaMalloc((void **)&d_knodes, sizeof(knode) * knodes_elem);
    cudaMalloc((void **)&d_currKnode, sizeof(long) * count);
    cudaMalloc((void **)&d_offset, sizeof(long) * count);
    cudaMalloc((void **)&d_keys, sizeof(int) * count);
    cudaMalloc((void **)&d_ans, sizeof(record) * count);

    cudaMemcpy(d_records, records, sizeof(record) * knodes_elem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, sizeof(knode) * knodes_elem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, sizeof(long) * count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, sizeof(long) * count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, sizeof(int) * count, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ans, ans, sizeof(record) * count, cudaMemcpyHostToDevice);

    kernel_gpu<<<blocksPerGrid, threadsPerBlock>>>(order, maxheight, count,
                                                   d_knodes, knodes_elem,
                                                   d_currKnode, d_offset,
                                                   d_keys, d_ans,
                                                   d_records);
    cudaDeviceSynchronize();

    cudaMemcpy(ans, d_ans, sizeof(record) * count, cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
           (float)(time1 - time0) / 1000000,
           (float)(time1 - time0) / (float)(time2 - time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
           (float)(time2 - time1) / 1000000,
           (float)(time2 - time1) / (float)(time2 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2 - time0) / 1000000);
}

