__global__ void kernel_gpu_2(int order, long maxheight, int count,
                             knode *knodes, long knodes_elem,
                             long *currKnode, long *offset,
                             long *lastKnode, long *offset_2,
                             int *start, int *end,
                             int *recstart, int *reclength) {
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    int threadsPerBlock = (order < 1024) ? order : 1024;

    for (int i = 0; i < maxheight; i++) {
        __shared__ long shared_offset;
        __shared__ long shared_offset_2;
        if (thid == 0) {
            shared_offset = offset[bid];
            shared_offset_2 = offset_2[bid];
        }
        __syncthreads();

        if (thid < threadsPerBlock) {
            int curr_node = currKnode[bid];
            int last_node = lastKnode[bid];
            if (curr_node < knodes_elem) {
                int key_left = knodes[curr_node].keys[thid];
                int key_right = knodes[curr_node].keys[thid + 1];
                int s = start[bid];
                if (key_left <= s && key_right > s) {
                    int idx = knodes[curr_node].indices[thid];
                    if (idx < knodes_elem) {
                        atomicMin(&shared_offset, idx);
                    }
                }
            }
            if (last_node < knodes_elem) {
                int key_left = knodes[last_node].keys[thid];
                int key_right = knodes[last_node].keys[thid + 1];
                int e = end[bid];
                if (key_left <= e && key_right > e) {
                    int idx = knodes[last_node].indices[thid];
                    if (idx < knodes_elem) {
                        atomicMin(&shared_offset_2, idx);
                    }
                }
            }
        }
        __syncthreads();

        if (thid == 0) {
            offset[bid] = shared_offset;
            offset_2[bid] = shared_offset_2;
            currKnode[bid] = shared_offset;
            lastKnode[bid] = shared_offset_2;
        }
        __syncthreads();
    }

    if (thid < threadsPerBlock) {
        int curr_node = currKnode[bid];
        if (curr_node < knodes_elem) {
            if (knodes[curr_node].keys[thid] == start[bid]) {
                recstart[bid] = knodes[curr_node].indices[thid];
            }
        }
    }
    __syncthreads();

    if (thid < threadsPerBlock) {
        int last_node = lastKnode[bid];
        if (last_node < knodes_elem) {
            if (knodes[last_node].keys[thid] == end[bid]) {
                reclength[bid] = knodes[last_node].indices[thid] - recstart[bid] + 1;
            }
        }
    }
}

